SELECT "" AS IMAGES, "Footwear" AS MAINGROUP, "6AE2" AS PRODUCTGROUP, "NP_FT_" & [product_Shoe_" & [Item.Product Family] AS COLLECTION, "10" AS SUBDIVISION, "Footwear" AS SUBLINE, Left$([Item.Product Sex],1) AS Gender, Left$([item.model item no_],1) & "P0" & Right$([item.model item no_],8) & "1" AS STYLE, [Item_1.Description 2] & " " & [variable code.description] & " " & " xxx sistemare [item.Variable Code]" AS DESCRIPTION
FROM ((((([Purchase Line] INNER JOIN Item ON [Purchase Line].No_ = Item.No_) LEFT JOIN UPCCodes ON Item.No_ = UPCCodes.[Item No_]) INNER JOIN [Purchase Header] ON [Purchase Line].[Document No_] = [Purchase Header].No_) INNER JOIN [Purchase Line] AS [Purchase Line_1] ON ([Purchase Line].[Document No_] = [Purchase Line_1].[Document No_]) AND ([Purchase Line].[Original Line No_] = [Purchase Line_1].[Line No_])) INNER JOIN [Variable Code] ON (Item.[Variable Code 01] = [Variable Code].[Variable Code]) AND (Item.[Variable Group 01] = [Variable Code].[Variable Group])) INNER JOIN Item AS Item_1 ON Item.[Model Item No_] = Item_1.No_
WHERE ((([Purchase Header].No_)="ODA-19-00006"));

